import React from "react";

function CategorySection() {
  let categories = [
    {
      name: "Śniadania",
      image:
        "https://images.unsplash.com/photo-1484723091739-30a097e8f929?auto=format&fit=crop&w=600&q=80"
    },
    {
      name: "Obiady",
      image:
        "https://images.unsplash.com/photo-1512058564366-18510be2db19?auto=format&fit=crop&w=600&q=80"
    },
    {
      name: "Kolacje",
      image:
        "https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=600&q=80"
    },
    {
      name: "Desery",
      image:
        "https://images.unsplash.com/photo-1551024601-bec78aea704b?auto=format&fit=crop&w=600&q=80"
    },
    {
      name: "Zupy",
      image:
        "https://images.unsplash.com/photo-1547592166-23ac45744acd?auto=format&fit=crop&w=600&q=80"
    },
    {
      name: "Sałatki",
      image:
        "https://images.unsplash.com/photo-1546069901-ba9599a7e63c?auto=format&fit=crop&w=600&q=80"
    },
    {
      name: "Makarony",
      image:
        "https://images.unsplash.com/photo-1621996346565-e3dbc646d9a9?auto=format&fit=crop&w=600&q=80"
    },
    {
      name: "Fit",
      image:
        "https://images.unsplash.com/photo-1490645935967-10de6ba17061?auto=format&fit=crop&w=600&q=80"
    },
    {
      name: "Wegańskie",
      image:
        "https://images.unsplash.com/photo-1512621776951-a57141f2eefd?auto=format&fit=crop&w=600&q=80"
    },
    {
      name: "Wegetariańskie",
      image:
        "https://images.unsplash.com/photo-1511690743698-d9d85f2fbf38?auto=format&fit=crop&w=600&q=80"
    },
    {
      name: "Wypieki",
      image:
        "https://images.unsplash.com/photo-1509440159596-0249088772ff?auto=format&fit=crop&w=600&q=80"
    },
    {
      name: "Napoje",
      image:
        "https://images.unsplash.com/photo-1497534446932-c925b458314e?auto=format&fit=crop&w=600&q=80"
    }
  ];

  return (
    <section className="section">
      <div className="container">
        <div className="section-header">
          <h2>Przeglądaj według kategorii</h2>
          <p>Wybierz kategorię i odkrywaj inspirujące przepisy.</p>
        </div>

        <div className="category-grid">
          {categories.map((category, index) => (
            <div className="category-circle-card" key={index}>
              <div className="category-circle-image-wrapper">
                <img
                  src={category.image}
                  alt={category.name}
                  className="category-circle-image"
                />
              </div>
              <h3 className="category-circle-title">{category.name}</h3>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

export default CategorySection;
